import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { ArticleEditableCard } from '../../../../includes';


const style = theme => ({
    root: {
    }
})
class _BlogEdit extends Component {
    constructor(props) {
        super(props);
        this.blog = props.location.state;
    }
    
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                <ArticleEditableCard {...this.blog}/>
            </div>
        );
    }
}


_BlogEdit.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const BlogEdit = connect(mapStateToProps)(withStyles(style)(_BlogEdit));
export {BlogEdit as default}